head.script:
/**
 * @event 
 * @name onpageload 
 * @description 화면 초기화
 */
scwin.onpageload = function () {
};



/**
 * @event 
 * @name onUdcCompleted 
 * @description UDC 완료
 */
scwin.onUdcCompleted = function () {
    scwin.globalVars();

    const codeOptions = [
        { grpCd: "OP117", compID: "acb_shiftClsCd" },
        { grpCd: "OP120", compID: "acb_cvsslShiftingCd" },
    ];

    $c.data.setCommonCode(codeOptions, scwin.f_OnLoad);
};




/**
 * @method 
 * @name globalVars 
 * @description 전역변수선언
 */
scwin.globalVars = function () {
    scwin.PcvsslMgntNo = $c.data.getParameter('cvsslMgntNo') ?? ''; // 본선관리번호
    scwin.PwrkDt = $c.data.getParameter('wrkDt') ?? ''; // 작업일자
    scwin.PshiftClsCd = $c.data.getParameter('shiftClsCd') ?? ''; // shift
};



/**
 * @method 
 * @name f_OnLoad 
 * @description onLoad 시
 */
scwin.f_OnLoad = function () {

    // 값 초기화
    lay_wrkIndictNo.setValue('');
    lay_completeProcYn.setValue('');

    const CONDITION_ITEM_COUNT = 12;
    for (let i = 0; i < CONDITION_ITEM_COUNT; i++) {
        $p.getComponentById('name' + [i + 1]).setValue('');
    };

    // 순차문제 처리
    mxTab.getChildren()[0].setSrc('/ui/ds/op/wrkplan/stvwrkplan/op_204_02_09b.xml');

    // 작업물량계획 Tab 내용 보이기
    mxTab.setSelectedTabIndex(0);

    if (scwin.PcvsslMgntNo != "" && scwin.PwrkDt != "" && scwin.PshiftClsCd != "") {
        ed_cvsslMgntNo.setValue(scwin.PcvsslMgntNo);	// 본선관리번호
        ica_wrkDt.setValue(scwin.PwrkDt);				// 작업일자
        acb_shiftClsCd.setValue(scwin.PshiftClsCd);	// Shift 구분코드
        scwin.f_DivHoldEachWorkPlanList();

    } else {
        acb_shiftClsCd.setSelectedIndex(0);	// acb_shiftClsCd 초기값 Setting(주간)
        ica_wrkDt.setValue($c.date.getServerDateTime('yyyyMMdd')); // 작업일자 Setting

        scwin.f_DivHoldEachWorkPlanList();	// 본선작업계획상세조회 테이블 생성
        scwin.f_cfEnableObjFalse();	// obj Enable False

        ed_cvsslMgntNo.focus();	// on_load focus
    };

    $c.gus.cfEnableObj(acb_wrkIndictNo, false);
    $c.gus.cfEnableObj(btn_no1, false);

    ed_cvsslMgntNo.focus();

    // 테스트 데이터
    // ed_cvsslMgntNo.setValue('F1110006');
    // ica_wrkDt.setValue('20100910');
    // acb_shiftClsCd.setValue('D');

    // ed_cvsslMgntNo.setValue('D0808584');
    // ica_wrkDt.setValue('20080825');
    // acb_shiftClsCd.setValue('D');

    // ed_cvsslMgntNo.setValue('F1807005');
    // ica_wrkDt.setValue('20180725');
    // acb_shiftClsCd.setValue('D');

    // ed_cvsslMgntNo.setValue('H2501011');
    // ica_wrkDt.setValue('20250120');
    // acb_shiftClsCd.setValue('D');

    // ed_cvsslMgntNo.setValue('D0808584');
    // ica_wrkDt.setValue('20080825');
    // acb_shiftClsCd.setValue('D');

};




/**
 * @method 
 * @name f_cfNoEnableObjFalse 
 * @description cfEnableObj False
 */
scwin.f_cfNoEnableObjFalse = function () {

    const iFrame0 = mxTab.getWindow(0);
    const iFrame1 = mxTab.getWindow(1);
    const iFrame2 = mxTab.getWindow(2);

    $c.gus.cfDisableObjects([
        button_main1,
        button_main2,
        button_main3,
        button_main4,
        iFrame0.button_gr3
    ]);

    $c.gus.cfDisableObjects([
        iFrame1.button_no2,
        iFrame1.button_no3,
        iFrame1.button_no4,
        iFrame1.button_no5,
        iFrame1.udc_grdButton,
        iFrame1.btn_save
    ]);

    $c.gus.cfDisableObjects([
        // iFrame2.button_no2,
        // iFrame2.button_no3,
        // iFrame2.button_no4,
        // iFrame2.button_no5,
        // iFrame2.button_no6
        iFrame2.udc_bottomGrd06Btn,
        iFrame2.udc_bottomGrd07Btn,
        iFrame2.udc_bottomGrd08Btn,
        iFrame2.btn_no11
    ]);

    // $c.gus.cfDisableObjects([
    //     iFrame2.button_no7,
    //     iFrame2.button_no8,
    //     iFrame2.button_no9,
    //     iFrame2.button_no10,
    //     iFrame2.button_no11
    // ]);

    $c.gus.cfEnableObj(iFrame1.btn_no1, false);
    $c.gus.cfEnableObj(iFrame2.btn_no1, false);

};



/**
 * @method 
 * @name f_cfNoEnableObjFalse 
 * @description cfEnableObj True
 */
scwin.f_cfYesEnableObjTrue = function () {

    const iFrame0 = mxTab.getWindow(0);
    const iFrame1 = mxTab.getWindow(1);
    const iFrame2 = mxTab.getWindow(2);

    $c.gus.cfEnableObjects([
        button_main1,
        button_main2,
        button_main3,
        button_main4,
        iFrame0.button_gr3
    ]);

    $c.gus.cfEnableObjects([
        iFrame1.button_no2,
        iFrame1.button_no3,
        iFrame1.button_no4,
        iFrame1.button_no5,
        iFrame1.udc_grdButton,
        iFrame1.btn_save
    ]);

    $c.gus.cfEnableObjects([
        // iFrame2.button_no2,
        // iFrame2.button_no3,
        // iFrame2.button_no4,
        // iFrame2.button_no5,
        // iFrame2.button_no6
        iFrame2.udc_bottomGrd06Btn,
        iFrame2.udc_bottomGrd07Btn,
        iFrame2.udc_bottomGrd08Btn,
        iFrame2.btn_no11
    ]);

    // $c.gus.cfEnableObjects([
    //     iFrame2.button_no7,
    //     iFrame2.button_no8,
    //     iFrame2.button_no9,
    //     iFrame2.button_no10,
    //     iFrame2.button_no11
    // ]);

};



/**
 * @method 
 * @name f_cfEnableObjFalse 
 * @description cfEnableObj False
 */
scwin.f_cfEnableObjFalse = function () {

    $c.gus.cfEnableObj(ica_wrkStDt, false);
    $c.gus.cfEnableObj(ed_wrkStHh, false);
    $c.gus.cfEnableObj(ica_wrkEndDt, false);
    $c.gus.cfEnableObj(ed_wrkEndHh, false);
    $c.gus.cfEnableObj(cbx_extdYn, false);
    $c.gus.cfEnableObj(cbx_ealyAtdYn, false);
    $c.gus.cfEnableObj(acb_cvsslShiftingCd, false);

};



/**
 * @method 
 * @name f_cfEnableObjTrue 
 * @description cfEnableObj True
 */
scwin.f_cfEnableObjTrue = function () {

    let enableValid = acb_shiftClsCd.getValue() == 'N' || acb_shiftClsCd.getValue() == 'M'
    $c.gus.cfEnableObj(ica_wrkStDt, enableValid);
    $c.gus.cfEnableObj(ed_wrkStHh, true);
    $c.gus.cfEnableObj(ica_wrkEndDt, true);
    $c.gus.cfEnableObj(ed_wrkEndHh, true);
    $c.gus.cfEnableObj(cbx_extdYn, true);
    $c.gus.cfEnableObj(cbx_ealyAtdYn, true);
    $c.gus.cfEnableObj(acb_cvsslShiftingCd, true);

};



/**
 * @method 
 * @name f_mainInput 
 * @description 입력 버튼 클릭
 */
scwin.f_mainInput = async function () {

    if (ds_main2.getRowCount() != 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_011, ["일일 작업계획"]); // "이미 존재하는 @입니다."
        return false;
    }

    if (ds_main9.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["Shift별 기준작업시간", "등록"]); // "@이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오."
        return false;
    };


    let jsonData = {
        "cvsslMgntNo": ed_cvsslMgntNo.getValue(),	// 본선관리번호
        "wrkDt": ica_wrkDt.getValue(),				// 작업일자
        "shiftClsCd": acb_shiftClsCd.getValue(),	// Shift 구분코드
    };

    ds_main2.setRowJSON(0, jsonData);

    scwin.f_cfEnableObjTrue();	// obj Enable True

    jsonData = ds_main9.getRowJSON(0);

    ica_wrkStDt.setValue(jsonData.wrkStDt);
    ed_wrkStHh.setValue(jsonData.wrkStHh);
    ica_wrkEndDt.setValue(jsonData.wrkEndDt);
    ed_wrkEndHh.setValue(jsonData.wrkEndHh);

};



/**
 * @method 
 * @name f_mainModify 
 * @description 수정 버튼 클릭
 */
scwin.f_mainModify = async function () {

    if (ds_main2.getRowCount() == 0) {
        await $c.gus.cfAlertMsg("%1할(된) %2이(가) 존재하지 않습니다.", ["수정", " 일일 작업계획"]); // "@할(된) @이(가) 존재하지 않습니다."
        return false;
    };

    scwin.f_cfEnableObjTrue();	// obj Enable True

};



/**
 * @method 
 * @name f_mainModify 
 * @description 조회 버튼 클릭
 */
scwin.f_Retrieve = async function () {

    // 검색조건 필수 입력 체크
    // 본선관리번호, 작업일자
    if (!await $c.gus.cfValidate([ed_cvsslMgntNo, ica_wrkDt, acb_shiftClsCd])) {
        return;
    };

    ds_combo1.removeAll();
    scwin.f_cfEnableObjFalse();	// obj Enable False
    // dma_search.UserStatus(1) = 1; // TODO - 확인필요

    let sbmObj = await $c.sbm.execute(sbm_search);	// submit(); 과 동일

    if (sbmObj.responseJSON.resultDataSet[0].Msg == "SUCC") {
        await scwin.sbm_search_submitdone(sbmObj);

        scwin.f_DivHoldEachWorkPlanList();
        scwin.f_GridIOCheck3();

        const iFrame1 = mxTab.getWindow(1);
        const iFrame2 = mxTab.getWindow(2);

        // op_204_02_10b 화면은 ds_hidden으로 처리함
        iFrame1.ds_hidden.set('txt_hcvsslMgntNo', ed_cvsslMgntNo.getValue());
        iFrame1.ds_hidden.set('txt_hwrkDt', ica_wrkDt.getValue());
        iFrame1.ds_hidden.set('txt_hshiftClsCd', acb_shiftClsCd.getValue());

        iFrame2.txt_hcvsslMgntNo.setValue(ed_cvsslMgntNo.getValue());
        iFrame2.txt_hwrkDt.setValue(ica_wrkDt.getValue());
        iFrame2.txt_hshiftClsCd.setValue(acb_shiftClsCd.getValue());

        // TODO - 동작확인 필요
        // iFrame2.ds_LkStepNo.Filter();
        // iFrame2.ds_LkStepNo2.Filter();
        // iFrame2.ds_LkStepNo3.Filter();
    };



};



/**
 * @method 
 * @name f_mainModify 
 * @description Main저장 버튼 클릭
 */
scwin.f_mainSave = async function () {

    const dsMain9Data = ds_main9.getRowJSON(0);

    if (ds_main2.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(
            "%1할(된) %2이(가) 존재하지 않습니다.",
            ["작성(변경)", " 일일 작업계획"]
        );
        return false;
    };

    // 검색조건 필수 입력 체크
    // 본선관리번호, 작업일자
    const validDateTime = await $c.gus.cfValidate([ica_wrkStDt, ed_wrkStHh, ica_wrkEndDt, ed_wrkEndHh])
    if (!validDateTime) return;

    if (ed_wrkStHh.getValue().length != 4) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["시간형식"]);
        ed_wrkStHh.focus();
        return false;
    };

    if (ed_wrkEndHh.getValue().length != 4) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_055, ["시간형식"]);
        ed_wrkEndHh.focus();
        return false;
    };

    if (ed_wrkStHh.getValue().slice(0, 2) > "23") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_021, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
        ed_wrkStHh.focus();
        return;
    };

    if (ed_wrkStHh.getValue().slice(2, 4) > "59") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkStHh.focus();
        return;
    };

    if (ed_wrkEndHh.getValue().slice(0, 2) > "24") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 시가 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    };

    if (ed_wrkEndHh.getValue().slice(0, 2) == "00" && ed_wrkEndHh.getValue().slice(2, 4) == "00") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    };

    if (ed_wrkEndHh.getValue().slice(0, 2) == "24" && ed_wrkEndHh.getValue().slice(2, 4) > "00") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    };

    if (ed_wrkEndHh.getValue().slice(2, 4) > "59") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_022, ["작업시간"]); // "@은(는) 분이 잘못되었습니다."
        ed_wrkEndHh.focus();
        return;
    };

    if (ica_wrkStDt.getValue() < dsMain9Data.wrkStDt ||
        ica_wrkStDt.getValue() > $c.date.addDate(dsMain9Data.wrkStDt, 1)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_030 + "Shift별 기준작업일자로부터 하루이후까지만 가능합니다", ["야간/심야의 작업시작일자"]);
        ica_wrkStDt.focus();
        return;
    };

    if (ica_wrkEndDt.getValue() == $c.date.addDate(dsMain9Data.wrkStDt, 1)) {
        if (ed_wrkEndHh.getValue() > '0700') {
            await $c.gus.cfAlertMsg("야간/심야의 작업종료시간은 07시 이전이어야 합니다.");
            ed_wrkEndHh.focus();			// 시작시간에 focus
            return;
        };
    };

    if (!$c.gus.cfIsAfterDate(ica_wrkStDt.getValue(), ica_wrkEndDt.getValue())) {		// 시작일자와 종료일자 비교하여 시작일자보다 종료일자가 크지 않도록 Check
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
        ica_wrkStDt.focus();			// 시작일자에 focus
        return;
    };

    if (ica_wrkStDt.getValue() == ica_wrkEndDt.getValue()) { // 시작일자와 종료일자가 동일할때
        if (!$c.gus.cfIsAfterDate(ed_wrkStHh.getValue(), ed_wrkEndHh.getValue())) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_058); // 시작시간이 종료시간 이전이어야 합니다.
            ed_wrkStHh.focus();			// 시작시간에 focus
            return;
        };
    };

    let sbmObj = await $c.sbm.execute(sbm_main);

    if (sbmObj.responseJSON.resultDataSet[0].Msg == "SUCC") {
        await scwin.sbm_main_submitdone(sbmObj);
    };

};



/**
 * @method 
 * @name f_mainModify 
 * @description 삭제 버튼 클릭 (전체 삭제 처리)
 */
scwin.f_mainDelete = async function () {

    if (ds_main2.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_004, ["일일 작업계획"]); // "삭제할 @이(가) 존재하지 않습니다."
        return false;
    };

    const retConfirm = await $c.win.confirm("삭제하시겠습니까");
    if (!retConfirm) return;

    let wrkIndictNo = ds_main2.getCellData(0, "wrkIndictNo");	// 작업지시번호
    sbm_delete.action = "/ds.op.wrkplan.stvwrkplan.DeleteDailyWorkPlanCMD.do?" +
        "wrkIndictNo=" + wrkIndictNo;

    let sbmObj = await $c.sbm.execute(sbm_delete);

    if (sbmObj.responseJSON.resultDataSet[0].Msg == "SUCC") {
        await scwin.sbm_delete_submitdone(sbmObj);
    };

};



/**
 * @method 
 * @name f_openPopUp 
 * @description 본선관리번호검색 팝업창 띄우기
 */
scwin.f_openPopUp = async function () {

    let data = new Array();
    data[0] = ed_cvsslMgntNo.getValue(); //본선관리번호
    data[1] = ""; //수출입구분코드

    let options = {
        type: 'browserPopup',
        width: '900px',
        height: '400px',
        popupName: '본선관리번호검색팝업',
    };

    let url = '/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml';
    let rtnValues = await $c.win.openPopup(url, options, data);

    if (rtnValues != null) {
        ed_cvsslMgntNo.setValue(rtnValues[0]); //본선관리번호
    };

};



/**
 * @method 
 * @name f_DivHoldEachWorkPlanList 
 * @description 본선작업계획상세조회 테이블 생성
 */
scwin.f_DivHoldEachWorkPlanList = function () {

    // 1.본선기본정보조회
    let vsslNm = ""; //선박명
    let lineNm = ""; //LINE명
    let shpCoNm = ""; //선사명
    let impPortcnt = ""; //수입항차
    let expPortcnt = ""; //수출항차
    let impRepKcg = ""; //수입대표화종
    let expRepKcg = ""; //수출대표화종
    let wrkPlNm = ""; //작업장명
    let arrvlportDtm = ""; //입항일시
    let deprtportDtm = ""; //출항일시		

    let focusedIdx = ds_main1.getRowPosition() ?? 0;
    let rowData = ds_main1.getRowJSON(focusedIdx);
    let rowCnt = ds_main1.getRowCount();

    if (rowCnt > 0) {
        vsslNm = rowData.vsslNm;
        lineNm = rowData.lineNm;
        shpCoNm = rowData.shpCoNm;
        impPortcnt = rowData.impPortcnt;
        expPortcnt = rowData.expPortcnt;
        impRepKcg = rowData.impRepKcg;
        expRepKcg = rowData.expRepKcg;
        wrkPlNm = rowData.wrkPlNm;
        arrvlportDtm = $c.gus.cfGetFormatStr(rowData.arrvlportDtm, "####/##/## ##:##");
        deprtportDtm = $c.gus.cfGetFormatStr(rowData.deprtportDtm, "####/##/## ##:##");
    };


    title10.setValue('선명');
    name10.setValue(vsslNm);
    title11.setValue('LINE');
    name11.setValue(lineNm);
    title12.setValue('선사');
    name12.setValue(shpCoNm);


    if (rowCnt == 0) {
        title1.setValue('항차');
        title2.setValue('대표화종');
        title3.setValue('수출입구분');
        title4.setValue('항차');
        title5.setValue('대표화종');
        title6.setValue('수출입구분');
        return;
    };

    if (rowData.impPortcnt != "") {  // 수입 
        title1.setValue('항차');
        name1.setValue(impPortcnt);
        title2.setValue('대표화종');
        name2.setValue(impRepKcg)
        title3.setValue('수출입구분');
        name3.setValue('수입');

    } else {
        title1.setValue('항차');
        name1.setValue('');
        title2.setValue('대표화종');
        name2.setValue('');
        title3.setValue('수출입구분');
        name3.setValue('');
    };


    if (rowData.expPortcnt != "") {  // 수출
        title4.setValue('항차');
        name4.setValue(expPortcnt);
        title5.setValue('대표화종');
        name5.setValue(expRepKcg);
        title6.setValue('수출입구분');
        name6.setValue('수출');

    } else {
        title4.setValue('항차');
        name4.setValue('');
        title5.setValue('대표화종');
        name5.setValue('');
        title6.setValue('수출입구분');
        name6.setValue('');
    };

    title7.setValue('작업장');
    name7.setValue(wrkPlNm);
    title8.setValue('입항(예정)일시');
    name8.setValue(arrvlportDtm);
    title9.setValue('출항(예정)일시');
    name9.setValue(deprtportDtm);

};



/**
 * @method 
 * @name f_GridIOCheck3 
 * @description 코드를 이름으로 전환(수입,수출)
 */
scwin.f_GridIOCheck3 = function () {

    let rowCnt = ds_main1.getRowCount();
    for (let i = 0; i < rowCnt; i++) {
        switch (ds_main1.getCellData(i, "impExpClsCd")) {
            case 'I': ds_main1.setCellData(i, 'impExpClsCd', "수입"); break;
            case 'O': ds_main1.setCellData(i, 'impExpClsCd', "수출"); break;
            default: break;
        };
    }


};



/**
 * @method 
 * @name f_ShiftRetrieve 
 * @description 주간 Shift 계획 불러오기 버튼 클릭
 */
scwin.f_ShiftRetrieve = async function () {
    if (lay_wrkIndictNo.innerHTML == "") {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_018, ["작업지시번호", "작업지시번호 생성"]); //"@이(가) 존재하지 않습니다.\n먼저 @을(를) 하십시오."
        return;
    }

    const iFrame0 = mxTab.getWindow(0);
    const iFrame1 = mxTab.getWindow(1);
    const iFrame2 = mxTab.getWindow(2);

    let selectIdx = acb_wrkIndictNo.getSelectedIndex();

    iFrame0.acb_wrkIndictNo.setSelectedIndex(selectIdx);
    iFrame1.acb_wrkIndictNo.setSelectedIndex(selectIdx);
    iFrame2.acb_wrkIndictNo.setSelectedIndex(selectIdx);

    // 주간 Shift 계획 불러오기
    iFrame0.scwin.f_ShiftRetrieve();
    iFrame1.scwin.f_search();
    iFrame2.scwin.f_search();

};



/**
 * @method 
 * @name f_RetrievePierCd 
 * @description 부두 조회(점소 선택시 해당 점소의 부두만 조회)
 */
scwin.f_RetrievePierCd = async function (param1, param2) {

    sbm_combo1.action = "/cm.zz.RetrieveComboCMD.do?" +
        "sysCd=DailyStevedoringWorkIndicationEBC" +
        "&queryId=retrieveWorkPlanListCombo" +
        "&param1=" + param1 +
        "&param2=" + param2;

    let sbmObj = await $c.sbm.execute(sbm_combo1);

    if (sbmObj.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_combo1_submitdone(sbmObj);
    };

};



/**
 * @method 
 * @name f_RetrievePierCd 
 * @description 부두 조회(점소 선택시 해당 점소의 부두만 조회)
 */
scwin.f_RetrievePierCdCall = async function () {
    await scwin.f_RetrievePierCd(txt_hcvsslMgntNo.getValue(), ds_main2.getCellData(0, "wrkIndictNo"));
};



/**
 * @method 
