/**
 * @event 
 * @name sbm_search_submit 
 * @description 조회 TR 요청 전
 */
scwin.sbm_search_submit = function (e) {

    let jsonData = dma_search.getJSON();

    jsonData.cvsslMgntNo = ed_cvsslMgntNo.getValue();
    jsonData.wrkDt = ica_wrkDt.getValue();
    jsonData.shiftClsCd = acb_shiftClsCd.getValue();

    dma_search.setJSON(jsonData);

};



/**
 * @event 
 * @name sbm_search_submitdone 
 * @description 조회 TR 정상
 */
scwin.sbm_search_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Code == -1) return;

    txt_hlobranCd.setValue(ds_main1.getCellData(0, "lobranCd"));
    txt_hlobranNm.setValue(ds_main1.getCellData(0, "lobranNm"));
    txtWrkIndictNo.setValue(ds_main2.getCellData(0, "wrkIndictNo"));

    ds_main2.setRowPosition(0);

    await scwin.ds_main2_OnLoadCompleted();
    await scwin.ds_main3_OnLoadCompleted();
    await scwin.ds_main4_OnLoadCompleted();
    await scwin.ds_main5_OnLoadCompleted();
    await scwin.ds_main6_OnLoadCompleted();
    await scwin.ds_main7_OnLoadCompleted();
    await scwin.ds_main8_OnLoadCompleted();

};



/**
 * @event 
 * @name ds_main2_OnLoadCompleted 
 * @description 조회 후 ds_main2
 */
scwin.ds_main2_OnLoadCompleted = async function () {

    const iFrame1 = mxTab.getWindow(1);
    const iFrame2 = mxTab.getWindow(2);

    if (ds_main2.getRowCount() == 0) {	// 조회한 ds_main2 의 rowCnt 가 0 일때
        lay_wrkIndictNo.setValue('');
        lay_completeProcYn.setValue("");

        iFrame1.ds_hidden.set('txt_wrkIndictNo', '');
        iFrame2.txt_wrkIndictNo.setValue("");

        await $c.gus.cfAlertMsg(MSG_CM_WRN_002); // "조회결과가 존재하지 않습니다."
        scwin.f_cfYesEnableObjTrue();
        return;
    };

    // 조회한 ds_main2 의 rowCnt 가 0 이 아닐때
    // 하역작업지시번호
    lay_wrkIndictNo.setValue(ds_main2.getCellData(0, "wrkIndictNo"));

    iFrame1.ds_hidden.set('txt_wrkIndictNo', ds_main2.getCellData(0, "wrkIndictNo"));
    iFrame2.txt_wrkIndictNo.setValue(ds_main2.getCellData(0, "wrkIndictNo"));

    // 완료처리여부
    let completeProcYn = ds_main2.getCellData(0, "completeProcYn");
    if (completeProcYn == 0) {
        completeProcYn = "NO";
        scwin.f_cfYesEnableObjTrue();
    }
    else {
        completeProcYn = "YES";
        scwin.f_cfNoEnableObjFalse();
    };

    lay_completeProcYn.setValue(completeProcYn);
    await scwin.f_RetrievePierCdCall();

};


