/**
 * @event 
 * @name ds_main3_OnLoadCompleted 
 * @description 조회 후 ds_main3
 */
scwin.ds_main3_OnLoadCompleted = async function () {

    const iFrame0 = mxTab.getWindow(0);

    $c.gus.cfCopyDataSet(ds_main3, iFrame0.ds_main3, "copyHeader=yes");

    let rowCnt = ds_main3.getRowCount();

    iFrame0.txt_totalRows.setValue(rowCnt);
    // iFrame0.txt_check.setValue(rowCnt); // 해당화면에 컴포넌트 없음

    if (ds_main2.getRowCount() > 0) {
        iFrame0.scwin.f_RetrievePierCdCall();
    } else {
        iFrame0.co_ds_combo1.removeAll();
    };

};



/**
 * @event 
 * @name ds_main4_OnLoadCompleted 
 * @description 조회 후 ds_main4
 */
scwin.ds_main4_OnLoadCompleted = async function () {

    const iFrame1 = mxTab.getWindow(1);

    $c.gus.cfCopyDataSet(ds_main4, iFrame1.ds_main4, "copyHeader=yes");

    if (ds_main4.getCellData(0, "tableFlag") == 306) {
        iFrame1.ds_main4.setCellData(0, "wrkStpCd", '004');
        let dataset = iFrame1.ds_main4.getAllJSON();
        iFrame1.ds_main4.removeAll();

        if (ds_main2.getCellData(0, "completeProcYn") == 0) {
            iFrame1.ds_main4.setJSON(dataset);
        };
    };

    let rowCnt = ds_main4.getRowCount();
    iFrame1.txt_totalRows.setValue(rowCnt);
    iFrame1.scwin.f_defaultCall();	// Key 값 수정 X

    if (ds_main2.getRowCount() > 0) {
        iFrame1.scwin.f_RetrievePierCdCall();
    } else {
        iFrame1.co_ds_combo1.removeAll();
    };

};



