scwin.sbm_main_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Code == -1) return;

    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
    // dma_search.UserStatus(1) = 1;
    let sbmObj = await $c.sbm.execute(sbm_search);	// 조회

    if (sbmObj.responseJSON.resultDataSet[0].Msg == "SUCC") {
        await scwin.sbm_search_submitdone(sbmObj);
    };

};



