/**
 * @event 
 * @name sbm_combo1_submitdone 
 * @description acb_wrkIndictNo item TR 정상
 */
scwin.sbm_combo1_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Code == -1) return;

    if (ds_combo1.getRowCount() > 0) {
        $c.gus.cfEnableObj(acb_wrkIndictNo, true);
        $c.gus.cfEnableObj(btn_no1, true);
    } else {
        $c.gus.cfEnableObj(acb_wrkIndictNo, false);
        $c.gus.cfEnableObj(btn_no1, false);
    };

    if (ds_main2.getRowCount() > 0) {
        if (ds_main2.getCellData(0, "completeProcYn") == 1) {
            $c.gus.cfEnableObj(btn_no1, false);
        };
    };

};
